CREATE TABLE `agents` (
  `id` int NOT NULL,
  `name` varchar(50) NOT NULL,
  `real_name` varchar(100) DEFAULT NULL,
  `id_val` varchar(50) DEFAULT NULL,
  `role_id` int DEFAULT NULL,
  `image_card` varchar(255) DEFAULT NULL,
